{!REQUIRESCRIPT("/soap/ajax/14.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/14.0/apex.js")} 

var records = sforce.connection.query("SELECT Id, IAW_R_Update_Income_Limits_Counter__c FROM HOMEtracker__Service_File__c Where id = '{!HOMEtracker__Service_File__c.Id}'");

var serviceFileRec = records.getArray('records')[0];

serviceFileRec.IAW_R_Update_Income_Limits_Counter__c = Number(serviceFileRec.IAW_R_Update_Income_Limits_Counter__c) + 1;

sforce.connection.update([serviceFileRec]);

window.location.reload();

if(serviceFileRec.IAW_R_Update_Income_Limits_Counter__c!=0){

alert('Warning! This button will only work once. If you need to make additional changes to the Income Limit fields, you must update them manually.');

}
